/**
 * Assign location score based on country
 * Assumes the country is already available in the incoming item (from previous node)
 * This avoids node-name lookups that cause hangs in recent n8n versions
 */

const newItems = [];

for (const item of $input.all()) {
  // Get country from incoming data - adjust field name if needed
  // Common possibilities: item.json.country, item.json.normalizedCountry, item.json.message.content.country, etc.
  let rawCountry = '';

  // Try most common paths - pick the one that matches your upstream output
  if (item.json.country) {
    rawCountry = item.json.country;
  } else if (item.json.normalizedCountry) {
    rawCountry = item.json.normalizedCountry;
  } else if (item.json.message?.content?.country) {
    rawCountry = item.json.message.content.country;
  } else if (item.json.output?.country) {
    rawCountry = item.json.output.country;
  }

  const country = (rawCountry || '').trim().toLowerCase();

  let locationScore = 0;

  // Your original tier lists (unchanged)
  const locUS = ['united states', 'usa', 'us'];
  const locTier2 = ['united kingdom', 'uk', 'canada', 'australia', 'new zealand'];
  const locWesternEurope = ['germany', 'france', 'netherlands', 'belgium', 'switzerland', 'austria', 'ireland', 'luxembourg'];
  const locNordic = ['sweden', 'norway', 'denmark', 'finland', 'iceland'];
  const locEastAsia = ['japan', 'south korea', 'korea', 'taiwan'];
  const locSingHK = ['singapore', 'hong kong'];
  const locMiddleEast = ['uae', 'israel', 'saudi arabia', 'qatar', 'kuwait', 'bahrain', 'oman'];
  const locOtherEU = ['spain', 'italy', 'portugal', 'poland', 'czech republic', 'greece', 'slovakia', 'hungary', 'lithuania', 'estonia', 'latvia', 'malta'];
  const locLatAm = ['brazil', 'mexico', 'argentina', 'chile', 'colombia', 'peru', 'uruguay', 'costa rica', 'panama'];
  const locSouthAsia = ['india', 'bangladesh', 'pakistan', 'sri lanka', 'nepal'];
  const locSEAsia = ['vietnam', 'indonesia', 'thailand', 'philippines', 'malaysia', 'myanmar', 'cambodia', 'laos', 'brunei'];
  const locEasternEurope = ['russia', 'ukraine', 'romania', 'bulgaria', 'serbia', 'croatia', 'slovenia', 'moldova', 'georgia', 'armenia', 'belarus', 'albania', 'montenegro', 'bosnia & herzegovina', 'north macedonia'];
  const locAfrica = ['south africa', 'nigeria', 'kenya', 'egypt', 'morocco', 'ghana', 'ethiopia', 'tanzania', 'tunisia', 'algeria', 'rwanda', 'botswana', 'uganda', 'senegal', 'zambia', 'namibia'];

  // Scoring
  if (locUS.includes(country)) {
    locationScore = 10;
  } else if (locTier2.includes(country)) {
    locationScore = 8;
  } else if (locWesternEurope.includes(country) ||
             locNordic.includes(country) ||
             locEastAsia.includes(country) ||
             locSingHK.includes(country)) {
    locationScore = 7;
  } else if (locMiddleEast.includes(country)) {
    locationScore = 6;
  } else if (locOtherEU.includes(country)) {
    locationScore = 4;
  } else if (locLatAm.includes(country)) {
    locationScore = 3;
  } else if (locSouthAsia.includes(country) ||
             locSEAsia.includes(country) ||
             locEasternEurope.includes(country)) {
    locationScore = 2;
  } else if (locAfrica.includes(country)) {
    locationScore = 1;
  } else {
    locationScore = 0;
  }

  newItems.push({
    json: {
      ...item.json,              // keep all previous fields
      normalizedCountry: rawCountry,  // original value for reference
      locationScore
    }
  });
}

return newItems;

/**
 * Templatized Code node: Score company headcount (staff size)
 * 
 * Users can customize:
 * - The ranges and their corresponding scores
 * - The field name/path where employee_count comes from
 * - Default score for unknown/missing values
 * 
 * How to customize:
 * 1. Edit the `scoreRanges` array below — add/remove/change ranges and scores
 * 2. Adjust `sourceFieldPath` if your employee_count is in a different spot
 * 3. Change `defaultScore` if you want a different fallback
 */

const newItems = [];

// ────────────────────────────────────────────────
// USER CONFIGURATION SECTION ── EDIT HERE
// ────────────────────────────────────────────────

const sourceNodeName = "Sanitize Description";          // Change if upstream node renamed
const sourceFieldPath = "employee_count";               // e.g. "output.employee_count", "data.staff", etc.

const defaultScore = 0;                                 // Score when count is missing / invalid / 0

// Define your scoring buckets here (lowest → highest)
// Format: { min: number, max: number, score: number }
// Use Infinity for "and above", null/undefined for open-ended
const scoreRanges = [
  { min: 1,    max: 10,   score: 3 },      // Very small (1–10)
  { min: 11,   max: 50,   score: 7 },      // Small-mid (11–50)
  { min: 51,   max: 200,  score: 10 },     // Sweet spot (51–200)
  { min: 201,  max: 500,  score: 9 },      // Mid-size (201–500)
  { min: 501,  max: 5000, score: 8 },      // Large (501–5000)
  { min: 5001, max: Infinity, score: 7 }   // Enterprise / very large (>5000)
];

// ────────────────────────────────────────────────
// END OF USER CONFIG ── NO NEED TO EDIT BELOW
// ────────────────────────────────────────────────

for (const item of $input.all()) {
  // Safely retrieve the employee count (modern n8n style)
  let staffCount = 0;

  // Try to get it from the configured source
  const sourceData = item.json;
  if (sourceFieldPath.includes('.')) {
    // Deep path (e.g. "output.employee_count")
    const parts = sourceFieldPath.split('.');
    let current = sourceData;
    for (const part of parts) {
      current = current?.[part];
      if (current === undefined) break;
    }
    staffCount = Number(current) || 0;
  } else {
    // Simple top-level field
    staffCount = Number(sourceData?.[sourceFieldPath]) || 0;
  }

  // Find matching range and assign score
  let headcountScore = defaultScore;

  for (const range of scoreRanges) {
    if (staffCount >= range.min && (range.max === Infinity || staffCount <= range.max)) {
      headcountScore = range.score;
      break;
    }
  }

  newItems.push({
    json: {
      ...item.json,
      staffCount,           // original value (cleaned to number)
      headcountScore
    }
  });
}

return newItems;

// Clean LinkedIn company description for Slack / short use
// Safe access + aggressive sanitization

const newItems = [];

for (const item of $input.all()) {
  let desc = "";

  // Safe path: get description from upstream "LinkedIn Agent" node
  const agentOutput = $("LinkedIn Agent").first()?.json?.output;
  if (agentOutput?.description) {
    desc = agentOutput.description;
  } else {
    // Fallback: try current item's json if description is already there
    desc = item.json.description || "";
  }

  // Sanitize for clean text output
  desc = desc
    .replace(/[\u2018\u2019\u201C\u201D]/g, "'")     // fancy quotes → normal
    .replace(/[\u2013\u2014]/g, "-")                 // dashes
    .replace(/\u2026/g, "...")                       // ellipsis
    .replace(/\r\n|\r|\n/g, " ")                     // newlines → space
    .replace(/\s+/g, " ")                            // collapse whitespace
    .trim();

  // Optional: cap length for Slack-ish contexts
  if (desc.length > 280) {
    desc = desc.slice(0, 277) + "...";
  }

  // Pass through original data + add cleaned field
  newItems.push({
    json: {
      ...item.json,
      sanitized_description: desc
    }
  });
}

return newItems;

/**
 * Templatized Code node: Normalize & Score Company Industry
 * 
 * Maps raw industry strings to broader categories and assigns scores.
 * 
 * Customization guide (edit in USER CONFIG section below):
 * 1. Add/remove/edit entries in `industryCategories`
 * 2. Adjust keyword matches (case-insensitive partial matches)
 * 3. Change fallback category & score
 * 4. Modify source field/path if needed
 */

const newItems = [];

// ────────────────────────────────────────────────
// USER CONFIGURATION SECTION ── EDIT HERE
// ────────────────────────────────────────────────

const sourceFieldPath = "output.industry";              // Path in incoming json, e.g. "industry", "output.industry", "data.company.industry"

const fallbackCategory = {
  category: "Other Industries",
  score: 3,
  note: "No strong match found"
};

const industryCategories = [
  {
    category: "Technology, Information and Media",
    score: 10,
    keywords: [
      "technology", "software", "it ", "information technology", "saas", "cloud",
      "cybersecurity", "artificial intelligence", "data", "internet", "computer",
      "digital", "tech", "ai", "ml", "platform", "it services", "it consulting"
    ]
  },
  {
    category: "Financial Services",
    score: 9,
    keywords: [
      "financial", "fintech", "insurance", "investment", "wealth management",
      "capital markets", "venture capital", "private equity"
    ]
  },
  {
    category: "Healthcare",
    score: 6,
    keywords: [
      "healthcare", "health", "medical", "biotech", "pharmaceutical", "life sciences",
      "hospital", "clinical", "wellness"
    ]
  },
  {
    category: "Retail & E-commerce",
    score: 6,
    keywords: [
      "retail", "e-commerce", "ecommerce", "shop", "store", "marketplace",
      "commerce", "online shopping"
    ]
  },
  {
    category: "Manufacturing",
    score: 6,
    keywords: [
      "manufacturing", "industrial", "production", "factory", "fabrication",
      "assembly", "engineering"
    ]
  },
  {
    category: "Professional Services / Consulting",
    score: 5,
    keywords: [
      "professional services", "consulting", "management consulting", "strategy consulting",
      "business consulting", "advisory", "accounting"
    ]
  },
  {
    category: "Advertising & Marketing",
    score: 6,
    keywords: [
      "advertising", "marketing", "ad tech", "ad agency", "digital marketing",
      "marketing agency", "branding"
    ]
  },
  {
    category: "Education",
    score: 4,
    keywords: [
      "education", "learning", "training", "school", "university", "academic",
      "edtech", "teaching"
    ]
  },
  {
    category: "Travel & Hospitality",
    score: 4,
    keywords: [
      "travel", "hospitality", "hotel", "tourism", "airline", "vacation",
      "accommodation"
    ]
  },
  {
    category: "Consumer Goods",
    score: 3,
    keywords: [
      "consumer goods", "fmcg", "consumer products", "packaged goods",
      "consumer brands"
    ]
  },
  {
    category: "Real Estate",
    score: 3,
    keywords: [
      "real estate", "property", "realty", "housing", "commercial property"
    ]
  },
  {
    category: "Entertainment & Media",
    score: 3,
    keywords: [
      "entertainment", "gaming", "games", "music", "movies", "media production",
      "film", "video", "broadcasting"
    ]
  }
  // Add more categories here as needed, highest priority first
];

// ────────────────────────────────────────────────
// END OF USER CONFIG ── NO NEED TO EDIT BELOW
// ────────────────────────────────────────────────

for (const item of $input.all()) {
  // Safely extract raw industry
  let rawIndustry = '';

  if (sourceFieldPath.includes('.')) {
    const parts = sourceFieldPath.split('.');
    let current = item.json;
    for (const part of parts) {
      current = current?.[part];
      if (current === undefined) break;
    }
    rawIndustry = (current || '').toString();
  } else {
    rawIndustry = (item.json?.[sourceFieldPath] || '').toString();
  }

  const normalized = rawIndustry.trim().toLowerCase();

  // Find best match (first match wins - order in array matters!)
  let matched = { ...fallbackCategory, originalIndustry: rawIndustry };

  for (const cat of industryCategories) {
    for (const kw of cat.keywords) {
      if (normalized.includes(kw)) {
        matched = {
          category: cat.category,
          score: cat.score,
          originalIndustry: rawIndustry
        };
        break; // Stop at first match
      }
    }
    if (matched.category !== fallbackCategory.category) break;
  }

  newItems.push({
    json: {
      ...item.json,
      normalizedIndustry: matched.category,
      originalIndustry: matched.originalIndustry,
      industryScore: matched.score
    }
  });
}

return newItems;

/**
 * Final Lead Scoring (Templatized)
 * Combines headcount, location, and industry scores into a 0–100 final score + qualitative rating.
 * 
 * Customization guide (edit in USER CONFIG section):
 * - Change weights for each component (they auto-normalize to 100)
 * - Adjust rating thresholds and labels
 * - Modify node names or field paths if upstream nodes change
 * - Add more sub-scores later if needed
 */

const newItems = [];

// ────────────────────────────────────────────────
// USER CONFIGURATION SECTION ── EDIT HERE
// ────────────────────────────────────────────────

const config = {
  // Source node names and field paths (update if renamed)
  sources: {
    headcount: { node: "Score Staff Count",   field: "headcountScore" },
    location:  { node: "Score Country",       field: "locationScore"  },
    industry:  { node: "Industry Scoring",    field: "industryScore"  }
  },

  // Weights (higher = more important) — will be normalized to total 100
  weights: {
    headcount: 1,   // e.g. give headcount more/less emphasis
    location:  1,
    industry:  1
  },

  // Rating tiers (thresholds from high → low)
  ratingTiers: [
    { min: 80, label: "Excellent Fit" },
    { min: 60, label: "Good Fit"      },
    { min: 40, label: "Moderate Fit"  },
    { min:  0, label: "Poor Fit"      }
  ],

  // Fallback if a score is missing/invalid
  defaultSubScore: 0
};

// ────────────────────────────────────────────────
// END OF USER CONFIG ── NO NEED TO EDIT BELOW
// ────────────────────────────────────────────────

for (const item of $input.all()) {
  // Helper to safely get a score from upstream
  const getScore = (source) => {
    try {
      return Number(item.json?.[source.field]) || config.defaultSubScore;
    } catch (e) {
      return config.defaultSubScore;
    }
  };

  // Extract individual scores (using incoming data, not node lookups)
  const headcountScore = getScore(config.sources.headcount);
  const locationScore  = getScore(config.sources.location);
  const industryScore  = getScore(config.sources.industry);

  // Weighted total (raw points)
  const totalRaw = 
    headcountScore * config.weights.headcount +
    locationScore  * config.weights.location  +
    industryScore  * config.weights.industry;

  // Normalize to max possible raw = sum of max scores × weights
  const maxPossible = 
    10 * config.weights.headcount +
    10 * config.weights.location  +
    10 * config.weights.industry;

  const finalScore = maxPossible > 0 ? Math.round((totalRaw / maxPossible) * 100) : 0;

  // Find matching rating
  let rating = config.ratingTiers[config.ratingTiers.length - 1].label; // fallback
  for (const tier of config.ratingTiers) {
    if (finalScore >= tier.min) {
      rating = tier.label;
      break;
    }
  }

  newItems.push({
    json: {
      output: {
        scores: {
          headcount: headcountScore,
          location:  locationScore,
          industry:  industryScore,
          totalRaw,
          finalScore,
          rating
        }
      }
    }
  });
}

return newItems;

const data = $input.item.json;

// Step 1: Recursively search for the first LinkedIn URL
function findLinkedInUrl(obj, path = '') {
  if (!obj || typeof obj !== 'object') return null;

  if (Array.isArray(obj)) {
    for (const item of obj) {
      if (typeof item === 'string' && item.includes('linkedin.com')) {
        return item;
      }
    }
    for (let i = 0; i < obj.length; i++) {
      const result = findLinkedInUrl(obj[i], `${path}[${i}]`);
      if (result) return result;
    }
  } else {
    for (const [key, value] of Object.entries(obj)) {
      if (typeof value === 'string' && value.includes('linkedin.com')) {
        return value;
      }
      const result = findLinkedInUrl(value, path ? `${path}.${key}` : key);
      if (result) return result;
    }
  }

  return null;
}

const rawLinkedInUrl = findLinkedInUrl(data);

// Step 2: Normalize the LinkedIn URL (vanity or numeric company page)
let cleanLinkedInUrl = null;
if (typeof rawLinkedInUrl === 'string') {
  // Match pattern like: https://www.linkedin.com/company/zeva-global-inc or /company/98872926
  const match = rawLinkedInUrl.match(/https?:\/\/(www\.)?linkedin\.com\/company\/[a-zA-Z0-9-]+/);
  if (match) {
    cleanLinkedInUrl = match[0].replace(/\/+$/, '') + '/'; // Ensure single trailing slash
  }
}

// Step 3: Fallback in case no valid LinkedIn URL is found
const safeLinkedInUrl = cleanLinkedInUrl || null;
const hasLinkedIn = safeLinkedInUrl !== null;

return {
  json: {
    domain: data.metadata?.sourceURL?.replace(/^https?:\/\//, '').split('/')[0] || '',
    originalUrl: data.metadata?.sourceURL || '',
    linkedInUrl: safeLinkedInUrl,
    hasLinkedIn,
    debugInfo: {
      rawLinkedInUrl,
      cleanLinkedInUrl,
      dataKeys: Object.keys(data),
      searchComplete: true
    }
  }
};

